#include <bits/stdc++.h>
using namespace std;
int main(){
    int t;
    long long n,m;
    scanf("%d",&t);
    while(t--){
        scanf("%lld%lld",&n,&m);
        long long tmp=(n+1)/2,sum=(n%2==0? (2+n)*n/2/2*2:(1+n)*(n/2+1)/2+(n-1)*(n/2)/2);
        //printf("%lld %lld\n",tmp,sum);
        if((tmp-m)%2==0){
            printf("%lld\n",sum-((1+(tmp-m)/2)*((tmp-m)/2)/2*2*4-(n%2)*(tmp-m)/2*4));
        }else{
        	//sum-((1+(tmp-m+1)/2)*((tmp-m+1)/2)/2*2-(1+(tmp-m+1)/2))*4-(n%2)*(tmp-m+1)/2*2-(n%2)*(tmp-m+1)/2*2;
            printf("%lld\n",sum-((1+(tmp-m)/2)*((tmp-m)/2)/2*2*4-(n%2)*(tmp-m)/2*4+4*((tmp-m+1)/2)));
        }
    }
    return 0;
}
